    /**
     * Removes all expired entries from the cache.
     */
    public int evictExpired() throws IOException {
        int evicted = 0;
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory, "*.json")) {
            for (Path file : stream) {
                try {
                    byte[] jsonBytes = Files.readAllBytes(file);
                    CacheEntry entry = objectMapper.readValue(jsonBytes, CacheEntry.class);
                    if (entry.isExpired()) {
                        Files.deleteIfExists(file);
                        evicted++;
                    }
                } catch (Exception e) {
                    // Corrupted file - remove it
                    Files.deleteIfExists(file);
                    evicted++;
                }
            }
        }
        return evicted;
    }

