    // --- Validation methods ---

    /**
     * Validates a cache entry after deserialization.
     * This is critical for security - we validate types and structure before use.
     */
    private <T> boolean validateCacheEntry(CacheEntry entry, String expectedKey, Class<T> expectedType) {
        if (entry == null) {
            System.err.println("Cache validation failed: null entry");
            return false;
        }

        // Validate key matches
        if (!expectedKey.equals(entry.getKey())) {
            System.err.println("Cache validation failed: key mismatch. Expected: " +
                    expectedKey + ", got: " + entry.getKey());
            return false;
        }

        // Validate the stored data type is in our allowed list
        if (!ALLOWED_TYPES.contains(entry.getDataType())) {
            System.err.println("Cache validation failed: disallowed type: " + entry.getDataType());
            return false;
        }

        // Validate the expected type matches or is compatible
        if (!isTypeCompatible(entry.getDataType(), expectedType.getName())) {
            System.err.println("Cache validation failed: type mismatch. Stored: " +
                    entry.getDataType() + ", expected: " + expectedType.getName());
            return false;
        }

        // Validate timestamps are reasonable
        long now = Instant.now().toEpochMilli();
        if (entry.getCreatedAtEpochMillis() > now + 60000) { // allow 1 minute clock skew
            System.err.println("Cache validation failed: future timestamp");
            return false;
        }

        // Validate data is not null
        if (entry.getData() == null) {
            System.err.println("Cache validation failed: null data");
            return false;
        }

        return true;
    }

    /**
     * Checks if the stored type is compatible with the expected type.
     */
    private boolean isTypeCompatible(String storedType, String expectedType) {
        if (storedType.equals(expectedType)) {
            return true;
        }
        // Allow LinkedHashMap to be read as HashMap
        if (storedType.equals(LinkedHashMap.class.getName()) && expectedType.equals(HashMap.class.getName())) {
            return true;
        }
        return false;
    }

    /**
     * Validates that a type is in the allowed whitelist.
     */
    private void validateType(String typeName) {
        if (!ALLOWED_TYPES.contains(typeName)) {
            throw new SecurityException("Type not allowed for caching: " + typeName +
                    ". Only whitelisted types are permitted.");
        }
    }

    /**
     * Validates a cache key to prevent path traversal attacks.
     */
    private void validateKey(String key) {
        if (key == null || key.isEmpty()) {
            throw new IllegalArgumentException("Cache key cannot be null or empty");
        }
        if (key.length() > 256) {
            throw new IllegalArgumentException("Cache key too long (max 256 characters)");
        }
        // Prevent path traversal
        if (key.contains("..") || key.contains("/") || key.contains("\\") ||
                key.contains("\0")) {
            throw new IllegalArgumentException("Cache key contains invalid characters");
        }
        // Only allow alphanumeric, dash, underscore, dot
        if (!key.matches("^[a-zA-Z0-9._-]+$")) {
            throw new IllegalArgumentException("Cache key contains disallowed characters. " +
                    "Only alphanumeric, dash, underscore, and dot are allowed.");
        }
    }

    /**
     * Computes a SHA-256 checksum for integrity verification.
     */
    private String computeChecksum(byte[] data) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(data);
            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }

    /**
     * Gets the file path for a cache key.
     */
    private Path getCacheFilePath(String key) {
        // Use a hash-based filename to avoid filesystem issues
        String safeFilename = computeChecksum(key.getBytes()).substring(0, 32) + ".json";
        Path resolved = cacheDirectory.resolve(safeFilename).normalize();
        // Ensure the resolved path is still within the cache directory
        if (!resolved.startsWith(cacheDirectory)) {
            throw new SecurityException("Path traversal detected for key: " + key);
        }
        return resolved;
    }

    /**
     * Checks if the cache size exceeds the maximum and evicts expired entries if needed.
     */
    private void checkCacheSize() throws IOException {
        long totalSize = 0;
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory, "*.json")) {
            for (Path file : stream) {
                totalSize += Files.size(file);
            }
        }
        if (totalSize > maxCacheSizeBytes) {
            evictExpired();
        }
    }

